var e=JSON.parse(`[{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"……이상. 클리포트 게임에 대한 보고를 마치겠습니다, 메데이아 경.","JPN":"……以上、クリフォトゲームの報告を終わります。メデイア卿。","ENG":"...That concludes the report on the Qliphoth Game, Dame Medea.","TWN":"……以上。關於逆卡巴拉遊戲的報告結束，美狄亞。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"고생하셨어요. 일의 전말을 듣고 나니 갑작스러운 긴급 소집도 납득이 가네요.","JPN":"お疲れさまでした。事情をうかがってようやく、あの突然の緊急招集にも合点がいきましたわ。","ENG":"Good work. Now that I've heard the full story, I can see why we were urgently called in.","TWN":"辛苦了。聽完事情的經過後，可以理解為什麼需要緊急召集了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"현재 에스테로사 경의 상태는 어떤가요?","JPN":"現在、エステロサ卿のご様子は？","ENG":"What's Dame Esterosa's condition?","TWN":"目前艾斯特洛索的狀態如何？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"같은 자리에 고개를 숙이신 채 움직이지 않고 계십니다.","JPN":"じっとうつむいた姿勢のまま、動かれません。","ENG":"She remains in the same spot, head bowed, completely still.","TWN":"在同一個位子低著頭，一動不動。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"아무래도 버밍엄 교수의 죽음이 여간 충격이셨던 것 같습니다.","JPN":"バーミンガム教授の死がかなりショックだったのだと思います。","ENG":"It seems Professor Birmingham's death was a severe shock to her.","TWN":"看來伯明罕教授的去世是個不小的打擊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그야 그렇겠죠. 그녀를 기사단에 들인 후견인은 다름아닌 버밍엄 교수였으니까요.","JPN":"それはそうでしょうね。彼女を騎士団に迎え入れる際に後押ししたのが、他ならぬバーミンガム教授でしたもの。","ENG":"Of course it was. After all, he was the one who sponsored her entry into the Order.","TWN":"那當然了。畢竟推薦她加入騎士團的導師正是伯明罕教授。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"심정을 이해못할 것은 아니나… 하필이면 원로원의 판단을 거스르다니.","JPN":"気持ちはわからなくもありませんが……よりによって元老院の判断に背くなんて。","ENG":"I don't blame her for how she feels... but defying the Elder Council's decision?","TWN":"我並不是不能理解你的心情……但為何偏偏要違背元老院的判斷呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"명분이 있었다 한들, 이번만큼은 치기어린 판단이었네요.","JPN":"いくら大義名分があったとはいえ、今回の判断は迂闊でした。","ENG":"Even with some justification, this time, that was a reckless move.","TWN":"即便有理由，這次也只是幼稚的判斷呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어… 그런데 아까부터 엄청 굳어 계시네요.","JPN":"あら……ところで、先程からずいぶんお顔が強張っていますね。","ENG":"Uh... You've been standing there awfully stiff. Did I make you uncomfortable somehow?","TWN":"呃……不過你從剛才開始就一直僵著呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"혹시 제가 불편할 짓이라도?","JPN":"もしかして私が何か気に障ることでも？","ENG":"Did I say something wrong?","TWN":"難道我做了讓你不舒服的事嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"아, 아닙니다! 별을 추종하는 기사로서 전 세대 분을 만난 것이 영광스러워서 그만…!","JPN":"い、いいえ！　星の追従者たる騎士として、前の世代の方にお会いできたのが光栄で、つい……！","ENG":"N-no, ma'am! It's just... As a knight who follows the stars, I'm honored to meet someone from the previous generation...!","TWN":"啊，不是的！作為追隨星辰的騎士，能見到前輩你是我的榮幸，所以才……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"비록 전임 기사단장으로 인해 의미가 퇴색되었지만, 전 세대 분들은 유례없는 황금세대라 불린 분들이 아닙니까?","JPN":"前騎士団長のことでその意味が薄れてしまったとはいえ、先代の方々は、かつて例のない黄金世代と呼ばれた方々ではありませんか。","ENG":"Though its significance may have been tarnished by the former commander, were not the previous generation hailed as an unparalleled golden generation?","TWN":"雖然由於前任騎士團長的原因意義有所減退，但上一代的人們不是被稱為史無前例的黃金一代嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그 중 백양궁의 기사인 메데이아 경을 만나다니… 이런 상황이지만 영광스러울 따름입니다!","JPN":"その中でも白羊宮の騎士であるメデイア卿に会えるなんて……こんな状況ですが、光栄の至りです！","ENG":"And meeting the Knight of Aries herself... Dame Medea, it's an honor, despite the circumstances!","TWN":"其中竟然遇到了白羊宮的騎士美狄亞……雖然是在這樣的情況下，但仍感到無比榮幸！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"과장된 표현이에요. 아직 견습이지만 지금 양자리의 기사는 제가 아니라 한솔이고요.\xA0\xA0\xA0","JPN":"おおげさですわ。まだ見習いとはいえ、今牡羊座の騎士を勤めているのはイチロウです。\xA0\xA0\xA0","ENG":"You flatter me. I may still hold the Armament due to family ties, but the current Knight of Aries is Hansol, not me.\xA0\xA0\xA0","TWN":"這是誇張的說法。我還是見習生，現在的白羊座騎士不是我，而是楊瀚。\xA0\xA0\xA0"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"가문이 얽힌 문제라 무구는 제 손에 있지만 그 점은 유의해주세요.","JPN":"家門内の事情で武具はまだ私が所持していますが、その点だけはお忘れなきよう。","ENG":"Please keep that in mind.","TWN":"因為涉及家族問題，武器雖然在我手上，但請注意這一點。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"넵. 주의하겠습니다!!","JPN":"はっ、気をつけます！！","ENG":"Understood! I'll be careful!","TWN":"好，我會注意的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아하하… 그럼, 현장으로 안내를 부탁드릴게요.","JPN":"あはは……では、現場へ案内をお願いしますわ。","ENG":"Ahaha... Well then, if you don't mind, please lead the way to the site.","TWN":"啊哈哈……那麼，請帶我去現場吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"알렌 버밍엄…… 카운터 아카데미 소속의 전술학 교사.","JPN":"アレン・バーミンガム……カウンターアカデミー所属の戦術学教師。","ENG":"Allen Birmingham... the tactics instructor from Counter Academy.","TWN":"艾倫·伯明罕……制裁者學院所屬的戰術學教師。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이전부터 그는 카운터 전술학 이외에 별의 무구의 연구에도 지대한 관심을 보였지.","JPN":"以前から彼は、カウンター戦術学の他に、星の武具の研究にも多大な関心を示していた。","ENG":"Even back then, his interest extended beyond Counter tactics, being deeply invested in researching the Star Armaments.","TWN":"從以前開始，他不僅對制裁者戰紀戰術學感興趣，還對星之武具的研究表現出極大的關注。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"만약 기사단에 협력한 게 흑심이었다면, 앞뒤는 맞아. 그들의 기예 역시 기사단과 것과 유사했으니.","JPN":"騎士団に協力したのも何か魂胆があってのこと、と思えば辻褄が合うわ。彼らの技も騎士団のものと似ていたし。","ENG":"If he aided the knights with ill intent, the timeline fits. Their techniques were suspiciously similar to ours.","TWN":"如果與騎士團合作是出於私心，那就說得通了。他們的技藝也與騎士團相似。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"문제는…….","JPN":"問題は……","ENG":"The problem is...","TWN":"問題是……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"겉모습과 달리, 그들의 무구가 관리국의 기술을 뛰어넘는다는 점이겠죠.","JPN":"見た目とは違い、彼らの武具が管理局の技術を遥かに超えているということでしょうね。","ENG":"That their Armaments surpass even the Administration's technology, despite appearances.","TWN":"與外表不同的是，他們的武器裝備超越了管理局的技術水準。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"그러니 마왕의 사도가 조디악 나이츠와 번거로운 유착 관계를 유지할 필요도 없고요.","JPN":"だから魔王の使徒がわざわざ、ゾディアックナイツと煩わしい癒着関係を保つ必要もない。","ENG":"Which means the Demon Lord's Apostle had no need to keep up a messy alliance with the Zodiac Knights.","TWN":"所以魔王的使徒也不需要與十二宮騎士團維持麻煩的關係。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇지 않나요, 메데이아 경?","JPN":"違いますか？　メデイア卿。","ENG":"Wouldn't you agree, Dame Medea?","TWN":"不是嗎，美狄亞？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어머. 오랜만에 뵙네요, 기관장 님. 그간 무탈하셨나요?","JPN":"あら、お久しぶりですね。機関長。お元気でしたか？","ENG":"Oh, Chief. It's been a while. Have you been well?","TWN":"哎呀，好久不見，機關長。最近一切都好嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"기관은 합중국의 대통령 각하를 모시는 임무를 맡았다 들었는데, 이런 곳에서 뵐 줄은 몰랐네요.","JPN":"機関は合衆国の大統領閣下を護衛する任務を任されたと聞きましたが、こんなところでお会いするとは。","ENG":"Last I heard, the Institution was serving the President of the States. I didn't expect to see you here.","TWN":"我聽說機關負責侍奉的是合眾國總統，沒想到會在這種地方見到你。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관원들만으로도 충분한 상황에 작전 코드, <color=#ffd34c>프리덤 스트라이크</color>가 발령되었으니까요.","JPN":"機関員だけでも十分な上に、作戦コード<color=#ffd34c>フリーダムストライク</color>が発令されましたから。","ENG":"Under normal circumstances, our agents would have been enough. But operation code <color=#ffd34c>Freedom Strike</color> was activated...","TWN":"僅靠機關成員就足夠的作戰代碼，<color=#ffd34c>自由之擊</color>已經發佈了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"장차 상대하게 될 적들을 가늠할 기회로 제격이었으니, 나설 이유로는 충분했답니다.","JPN":"将来相手するであろう敵の力を測るいい機会でしたし、表に出る理由としては十分でした。","ENG":"It became the perfect opportunity to gauge the strength of our future enemies. That was a reason enough for me to come.","TWN":"這正是評估將來要對付的敵人的最好機會，所以我有足夠的理由出動了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아하하… 여전히 사명감이 투철하시네요. 싸움을 방관하던 제가 부끄러울 따름이에요.","JPN":"あはは……相変わらず使命感の強いお方ですのね。戦いを傍観していた自分を恥ずかしく思います。","ENG":"Ahaha... You're as dutiful as ever. I feel ashamed for standing on the sidelines.","TWN":"啊哈哈…你依然充滿使命感呢。對於曾經旁觀戰鬥的我來說，真是感到慚愧啊。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"겸손하시긴. 퇴역 상태나 다름없는 당신이라면 현장에 파견되지 않을 수 있었을 겁니다.","JPN":"ご謙遜を。退役状態同然のあなたなら、現場への派遣を容易に断ることもできたはず。","ENG":"You're too modest. As someone effectively retired, no one would've blamed you for not deploying.","TWN":"你真謙虛。以你退役的狀態，可能不會被派遣到現場。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데도 이곳에 오신 이유는 분명 후임들이 걱정되어서겠죠.","JPN":"それなのにここに来た理由は、きっと後輩たちを心配してのことでしょう。","ENG":"And yet, you're here. Likely because you were concerned for your successors.","TWN":"即便如此，你來這裡的原因肯定是因為擔心後輩們吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"비록 현 기사단장의 혈육인 전임 기사단장은 자취를 감춰버렸으나…….","JPN":"現騎士団長の血縁である、前騎士団長は現在行方不明となっていますが……","ENG":"Though the former commander, kin to the current one, has disappeared without leaving a trace..","TWN":"雖然現任騎士團長的血親——前任騎士團長已經銷聲匿跡……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전 세대 기사 분들은 모두 명예를 위해 싸우는 긍지 높은 기사였으니까요.","JPN":"先代の騎士たちは皆、名誉のために戦う誇り高き騎士でしたから。","ENG":"The previous generation of knights were proud warriors who fought for honor.","TWN":"上一代的騎士們都是為了榮譽而戰的高傲騎士。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……그건.","JPN":"……それは。","ENG":"...That's.","TWN":"……那是。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨! 대체 어디로 사라지신 겁니까!","JPN":"お嬢様！　いったいどこに行かれたのですか！","ENG":"Lady Elizabeth! Where did you disappear to?!","TWN":"小姐！到底去哪了！"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"사태가 끝났으니 뒤처리를 해야 한다고 대체 몇 번을–.","JPN":"事態が収まったから、後始末をしないといけないと何度も……","ENG":"How many times have I told you that we need to handle the cleanup now that the situation's–","TWN":"事態已經結束了，我到底要說多少次才能讓你們收拾殘局——。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실례. 잠시 통신기에 혼선이 일어난 모양이네요.","JPN":"失礼。通信に混線が生じたようですわ。","ENG":"Excuse me. Seems we've got some interference on the line.","TWN":"抱歉，通訊設備似乎出現了一些干擾。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모처럼 교양 있는 분과 이야기 꽃을 피우려 하는데, 정말이지.","JPN":"せっかく教養のある方との話に花を咲かせようとしているところでしたのに。","ENG":"Here I was, enjoying a rare, cultured conversation, when...","TWN":"難得遇到一位有教養的人，真想好好聊聊。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"예. 아쉽지만 티타임은 다음 기회로 미뤄야겠어요.","JPN":"そうですね、残念ながらティータイムはまた今度にしないといけませんわね。","ENG":"Yes, a shame. Looks like we'll have to postpone tea time for now.","TWN":"是的。雖然有些遺憾，但下午茶時間還是留到下次吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"실례가 안된다면 현장 내용의 공유를 부탁드려도 괜찮을까요?","JPN":"よろしければ、現場の情報を共有していただけますでしょうか？","ENG":"Would it be all right if I asked you to share what's happening on the ground?","TWN":"如果不失禮的話，我可以請你分享一下現場的內容嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론이죠. 현재 투입된 태스크포스들의 도움으로 알아낸 사실입니다만.","JPN":"もちろんです。今投入されているタスクフォースの協力でわかったことですが。","ENG":"Of course. This is what we've learned thanks to the support of the deployed TASKFORCEs.","TWN":"當然。目前是透過投入的特遣勢力的幫助了解到的事實。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마왕의 죽음으로 성역의 모든 것이 사라질 것이라는 예상과 달리.","JPN":"魔王の死により聖域のすべてが消えるだろうという予想とは異なり……","ENG":"Contrary to predictions that the Sanctuary would vanish with the Demon Lord's death...","TWN":"與預期相反，隨著魔王的死亡，聖域的一切並沒有消失。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"고유무장을 비롯한 그들의 잔재가 여전히 남아있는 것으로 추정됩니다.","JPN":"固有武装をはじめとした彼らの残滓はまだ残っていると推定されます。","ENG":"Their remnants, including their Unique Gear, are still present.","TWN":"推測他們的遺留物，包括專屬裝備，仍然存在。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이는 다른 도플갱어 타입 침식체들이 사라진 것과 대조적인 부분이기도 하죠.","JPN":"これは、別のドッペルゲンガータイプ侵食体が姿を消したことと対照的な点でもあります。","ENG":"It's a stark contrast to the Doppelganger-type C.O., which has completely disappeared.","TWN":"這與其他二重身型侵蝕體消失的情況形成了對比。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"현장중계를 통해 확인했습니다. 그들의 고유무장은 기사단의 것과 유사하더군요.","JPN":"現場の中継で確認いたしました。彼らの固有武装は、騎士団のものと酷似していましたね。","ENG":"I saw it on the live broadcast. Their Unique Gear closely resembled those of our Order.","TWN":"透過現場轉播確認了。他們的專屬武裝與騎士團的相似。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"조금이라도 살펴보고 싶은데… 혹시 무구가 어떻게 되었는지 알 수 있을까요?","JPN":"少しでも実物を見てみたいところですが……武具は今どこにあるかご存じですか？","ENG":"I'd like to examine them... Do we know what became of the Armaments?","TWN":"我想稍微查看一下……能知道武器怎麼樣了嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"유감스러우나 관리국이 영치하고 있기에 당장 확인하는 건 힘들 것 같군요.","JPN":"残念ながら、管理局が預かっているため、すぐに実物を確認するのは難しいと思います。","ENG":"Unfortunately, the Administration has secured them. So immediate access isn't possible.","TWN":"很遺憾，由於管理局正在扣押，暫時無法確認。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"무엇보다, 그것들 중 일부의 행방은 파악되지 않고 있고요.","JPN":"何より、それらの一部に関しては所在が確認されていないので。","ENG":"And worse, some of them are currently unaccounted for.","TWN":"最重要的是，其中一些的下落尚未查明。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"무구가 사라졌단 소리인가요?","JPN":"武具が消えたということですか？","ENG":"You mean the Armaments have gone missing?","TWN":"是說武器消失了嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"예. 남아있는 무구가 특별할 뿐. 일각에서는 마왕의 죽음으로 인한 소실 현상이라 말하지만…….","JPN":"はい。むしろ武具が残っている方が特殊なケースで、一部では、魔王の死による消失現象だと言われていますが……","ENG":"Yes. The few that remain are notable, but others may have vanished. Some say it's due to the Demon Lord's death...","TWN":"是的。僅僅是剩下的武器特別罷了。有些人說這是因為魔王的死亡導致的消失現象……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오랜 세월을 기관에 몸담은 자로서 확신할 수 있어요.","JPN":"長い間機関に所属している私にはわかります。","ENG":"But as someone who's been in the Institution for years, I can tell you this much.","TWN":"作為在機構中待了多年的一員，我可以確信這一點。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마왕. 그리고 휘하의 사도들이 부리는 힘은 결코 등한시할 만한 것이 아니에요.","JPN":"魔王、そしてその旗下の使徒たちが発揮する力は決して見くびっていいようなものではありません。","ENG":"The powers wielded by the Demon Lord and Apostles are not to be underestimated.","TWN":"魔王，以及他麾下的使徒們所施展的力量絕對不可輕視。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"낮은 가능성이지만, 그들 내부에…….","JPN":"可能性は低いですが、彼らの中に……","ENG":"There's a small chance that within their ranks...","TWN":"雖然可能性很低，但在他們內部……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이런, 잔소리꾼이 보채느라 통신기가 말이 아니네요.","JPN":"はあ。どこかの小言好きが騒いでいて、通信機が使いものになりませんね。","ENG":"Ugh, that nag's blowing up my comms again. I can't hear myself think.","TWN":"哎呀，嘮叨鬼還在催呢，通訊器都快壞掉了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"죄송하지만 다른 내용은 기관원들을 통해 전달 드려도 괜찮을까요?","JPN":"すみませんが、続きは機関員を通してお伝えしてもよろしいかしら。","ENG":"Sorry, but may I have the rest relayed through my agents?","TWN":"抱歉，可以通過其他職員傳達內容嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"물론이죠. 바쁘신 와중에 귀한 시간을 내주셔서 감사합니다.","JPN":"もちろんですわ。お忙しい中時間を割いていただいて感謝します。","ENG":"Of course. Thank you for your time, especially with everything going on.","TWN":"當然了。感謝你在百忙之中抽出寶貴時間。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"혹여 기사단이 알게 되는 게 있다면 기관에게도 공유드릴 것을 약속드릴게요.","JPN":"今後騎士団が新しい情報を入手したら、機関にも共有させていただきます。","ENG":"If the knights learn anything new, we'll share it with the Institution as well.","TWN":"如果騎士團發現了什麼，我保證會與機關分享。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"예. 그럼 이만 가보겠습니다.","JPN":"ええ、それでは、ごきげんよう。","ENG":"Thank you. Then I'll excuse myself.","TWN":"好的，那我就先告辭了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다른 기사분들에게도 안부 전해주시길.","JPN":"騎士の皆さんにもよろしくお伝えください。","ENG":"Please give my regards to the other knights.","TWN":"請代我向其他騎士們問好。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"표정 관리하느라 애썼네. 높으신 분들을 상대하는 건 이래서 귀찮다니까.","JPN":"表情に気を使って疲れたわ。お偉い方々の相手はこれだから面倒なのよ。","ENG":"Keeping a straight face takes effort. Dealing with high-ranking officials is such a chore.","TWN":"辛苦了。應對那些高層人物真是麻煩啊。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이런 상황에 옛날 일을 들먹이다니. 그럴 의도가 아니라도 심보가 나쁘다고.","JPN":"この状況に昔の話を持ち出すなんて、わざとじゃなかったとしても、意地が悪いわ。","ENG":"Bringing up old memories in a situation like this. Even if it wasn't intentional, it's a bit cruel.","TWN":"在這種情況下提起過去的事情。即使不是故意的，也顯得心術不正。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"기사들의 싸움. 그 와중에 무구가 사라졌다라…….","JPN":"騎士たちの戦いの中で武具が消えた、か……","ENG":"Knights in battle. And now the Armaments have gone missing...","TWN":"騎士們的戰鬥。在那過程中武器消失了……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부로 돌아가야겠어.","JPN":"本部に帰らないと。","ENG":"I should return to HQ.","TWN":"我得回總部了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"혹시 모르니… 주교 영감을 만나봐야겠지.","JPN":"念のため……主教のジジイに会ったほうがいいわね。","ENG":"Just in case... I should pay a visit to His Holiness, the Bishop.","TWN":"以防萬一……還是去見見主教吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};